INSERT INTO showcase_sections (id, theme, title, display_order)
VALUES
    (1, 'summer-mood', '여름의 무드', 1),
    (2, 'brand-stories', '브랜드 스토리', 2);
INSERT INTO showcases (id, showcase_section_id, title, description, image_url, start_date, end_date, is_featured, display_order)
VALUES
    (1, 1, '가볍게 움직이는 여름 살로몬', '자연이 이루는 선에서 영감 받아 직선과 곡선이 균형을 이루는 구조적 실루엣을 제공하는 슬레이트 시리즈입니다.', 'showcases/showcase_01.png', '2026-05-13', '2026-05-26', TRUE, 1),
    (2, 1, '소소한 움직임 속 아름다움 앙개', '특별한 목적 없이 가볍게 움직이는 순간, 자연스러운 페미닌이 드러나요. 편안함 속에서 발견하는 우연한 재미를 담은 26SS 컬렉션을 만나보세요.', 'showcases/showcase_02.png', '2026-05-13', '2026-05-26', TRUE, 2),
    (3, 1, '향기를 입은 실루엣, 플로움', '조향사의 하루 속, 절제된 우아함과 실루엣으로 완성된 플로움', 'showcases/showcase_03.jpg', '2026-05-13', '2026-05-26', FALSE, 3),
    (4, 1, '여름의 공기를 담은 침실 핀카', '무더위가 찾아오기 전, 새롭게 출시된 핀카의 여름 베딩과 함께 시원한 여름을 준비해보세요.', 'showcases/showcase_04.png', '2026-05-13', '2026-05-26', FALSE, 4),
    (5, 1, '겨드랑이도 얼굴처럼 하우스오브밸런스', '데오드란트를 넘어선 언더암 스킨케어. 냄새 케어부터 피부 컨디션까지 섬세하게 관리하는 허브 데오드란트 컬렉션을 만나보세요.', 'showcases/showcase_05.png', '2026-05-13', '2026-05-24', FALSE, 5),
    (6, 1, '마르세유의 여름 폴로 랄프 로렌', '푸른 해변의 감성을 담은 서머 컬렉션이 도착했어요. 시원한 소재와 품격 있는 디자인으로 여름을 더욱 특별하게 만들어보세요.', 'showcases/showcase_06.jpg', '2026-05-13', '2026-05-26', FALSE, 6),
    (7, 1, '햇살 한 모금 에이보브하우스', '여름의 팔레트로 물든 햇살의 색감이 어우러지는 계절, 햇살 아래 더욱 돋보이는 계절의 분위기를 가볍고 산뜻하게 담아낸 컬렉션입니다.', 'showcases/showcase_07.png', '2026-05-13', '2026-05-26', FALSE, 7),
    (8, 1, '나에게 집중하는 시간 부디무드라', '불필요한 움직임을 내려두고 오롯이 나를 마주하는 순간. 이효리와 부디무드라가 함께 전하는 요가 라이프스타일이 일상 속에 자리해요.', 'showcases/showcase_08.jpg', '2026-05-13', '2026-05-26', FALSE, 8),
    (9, 1, '좋은 하루는 편한 옷으로부터 프론투라인', '움직임과 휴식의 경계를 유연하게 넘나드는 웰니스 웨어. 이청아와 함께한 26SS 컬렉션으로 일상의 새로운 밸런스를 경험해보세요.', 'showcases/showcase_09.png', '2026-05-13', '2026-05-26', FALSE, 9),
    (10, 1, '뉴 클래식 프레쉬 빈티지 인 썸머 브렌다 브렌든 서울', '7,80년대 아메리칸 캐주얼의 감성을 여름의 색감으로 풀어냈어요. 뉴 클래식 프레쉬 빈티지 인 썸머 컬렉션을 지금 만나보세요.', 'showcases/showcase_10.jpg', '2026-05-13', '2026-05-26', FALSE, 10),
    (11, 1, '늘 함께하는 사이 론론', '고양이와 포니가 나란히 서 있는 론론의 여섯 번째 컬렉션. 서로 다르지만 자연스럽게 어울리는 두 관계처럼, 편안하고 로맨틱한 여름 이지웨어를 만나보세요.', 'showcases/showcase_11.png', '2026-05-12', '2026-05-26', FALSE, 11),
    (12, 1, '지중해의 여유로운 시간 기준', '2000년대 스페인 팔마의 따스한 햇살과 청량한 바다를 담았어요. 해안 절벽과 물결에서 영감받은 유려한 실루엣으로 여름의 무드를 표현합니다.', 'showcases/showcase_12.png', '2026-05-12', '2026-05-25', FALSE, 12),
    (13, 1, '쁘띠 사이즈로 만나는 714센터', '인기 마고백을 더 작고 사랑스럽게 담았어요. 신규 컬러까지 추가되어 여기에만 있는 특별한 라인업을 만나보세요.', 'showcases/showcase_13.png', '2026-05-12', '2026-05-25', FALSE, 13),
    (14, 1, '순수한 본능을 깨우는 여름 애프터프레이', '2026 여름 컬렉션이 도착했어요. 내면 깊은 곳의 순수한 자아를 동시대적 언어로 풀어낸 프리스틴 차일드를 만나보세요.', 'showcases/showcase_14.png', '2026-05-12', '2026-05-25', FALSE, 14),
    (15, 1, '천천히 열어가는 계절 해브해드', '가벼워지는 공기 속에서 몸과 마음을 편안하게 풀어가는 시간이에요. 도시 생활의 작은 순간들을 담백하게 채울 여름 옷을 만나보세요.', 'showcases/showcase_15.png', '2026-05-12', '2026-05-25', FALSE, 15),
    (16, 1, '90년대를 재해석한 미니멀 디애퍼처', '90년대 미니멀리즘을 현대의 시선으로 풀어낸 감각을 만나보세요.', 'showcases/showcase_16.png', '2026-05-12', '2026-05-25', FALSE, 16),
    (17, 1, '작고 순수했던 여름의 기억 무드에디션', '잊고 있던 마음의 조각들을 모아 당신만의 계절을 완성해보세요. 시간이 지나도 변하지 않는 가치를 담아 선물 같은 하루를 선사해요.', 'showcases/showcase_17.png', '2026-05-12', '2026-05-25', FALSE, 17),
    (18, 1, '뜨겁지만 가볍게 지치지만 경쾌하게 포기무디', '여름의 열기 속에서도 경쾌한 발걸음을 이어가요. 우리들의 여름을 담은 포기무디의 써머 슈즈를 소개해요.', 'showcases/showcase_18.png', '2026-05-12', '2026-05-25', FALSE, 18),
    (19, 1, '나를 표현하는 순간 오하입', '머릿결에서 시작해 바디, 그리고 향기까지. 매일 반복되는 루틴을 특별한 순간으로 바꾸는 케어를 만나보세요.', 'showcases/showcase_19.png', '2026-05-12', '2026-05-25', FALSE, 19),
    (20, 1, '기록을 완성하는 순간 라미', '하이델베르크에서 완성되는 정교한 필기구를 만나보세요. 디자인부터 조립까지, 한 곳에서 이뤄지는 장인정신이 담긴 신제품이 도착했어요.', 'showcases/showcase_20.png', '2026-05-12', '2026-05-18', FALSE, 20),
    (21, 1, '정제된 여름의 선 수아마르', '가볍게 흐르는 소재와 절제된 실루엣으로 완성한 여름 컬렉션. 자연스러운 아름다움이 일상에 스며들어요.', 'showcases/showcase_21.png', '2026-05-12', '2026-05-25', FALSE, 21),
    (22, 1, '기다려온 블랙 에디션 인스탁스', '와이드 400 블랙 런칭 소식을 전해요. 세련된 블랙 컬러와 넓은 프레임으로 일상의 감성을 기록해보세요.', 'showcases/showcase_22.png', '2026-05-12', '2026-05-25', FALSE, 22),
    (23, 1, '함께라 더 자연스러운 여름 스노우피크 어패럴', '문지원&신우재 커플과 함께한 특별한 여름날. 자연 속에서 더욱 빛나는 일상을 경험해 보세요. 아웃도어와 일상의 경계를 허무는 스타일을 만나보세요.', 'showcases/showcase_23.png', '2026-05-11', '2026-05-24', FALSE, 23),
    (24, 1, '시간이 증명하는 가치 이얼즈어고', '변하지 않는 디자인과 엄선된 소재로 완성한 여름 컬렉션. 오래도록 함께할 옷을 단독 할인으로 만나보세요.', 'showcases/showcase_24.png', '2026-05-11', '2026-05-24', FALSE, 24),
    (25, 1, '향으로 오늘을 바꾸는 이구어퍼스트로피', '내가 선택한 향으로 하루의 순간을 완성하는 일. 29Apostrophe가 당신의 일상에 어울리는 향을 제안합니다.', 'showcases/showcase_25.png', '2026-05-11', '2026-05-25', FALSE, 25),
    (26, 1, '여름을 빛내줄 도트 컬렉션', '나이키의 대표아이템 코르테즈와 에어 리프트가 도트컬렉션과 함께 돌아왔어요.', 'showcases/showcase_26.png', '2026-05-11', '2026-05-24', FALSE, 26),
    (27, 1, '시간이 증명하는 우아함 스르비', '여성의 아름다움을 창의적으로 표현하는 스르비. 세련된 디테일과 현실적인 감각이 조화를 이루며, 시간을 견디는 가치 위에 고감도 스타일을 완성해요.', 'showcases/showcase_27.jpg', '2026-05-11', '2026-05-24', FALSE, 27),
    (28, 1, '왜곡된 현실 속 아름다움 레이브', '완벽함을 향한 시선에서 벗어나 불완전함 속의 균형을 탐구해요. 조화롭지만 어딘가 어긋난 듯한 감각, 그 속에서 발견하는 진짜 세련됨을 핫서머 선발매로 가장 먼저 만나요.', 'showcases/showcase_28.jpg', '2026-05-11', '2026-05-24', FALSE, 28),
    (29, 1, '자연 그대로의 균형 러베', '성분은 자연에서, 설계는 과학적으로. 불필요한 것을 덜어낸 무향 기반의 스킨리빙 제품을 만나보세요.', 'showcases/showcase_29.jpg', '2026-05-11', '2026-05-24', FALSE, 29),
    (30, 1, '나폴리의 산들바람 지노키오', '가볍게 스치는 바람처럼, 여유로운 여름을 담은 컬렉션 breeze를 소개해요. 바랜 듯 부드러운 컬러와 절제된 디자인으로 편안한 여름의 장면을 완성합니다.', 'showcases/showcase_30.jpg', '2026-05-11', '2026-05-17', FALSE, 30),
    (31, 1, '두피 컨디션별 맞춤 설계 차홍', '25년간 쌓아온 전문가의 노하우로 완성한 스캘프 포뮬러 7. 유분, 열감, 탄력, 민감함까지 달라지는 두피 상태에 맞춰 설계된 새로운 샴푸를 만나보세요.', 'showcases/showcase_31.jpg', '2026-05-11', '2026-05-24', FALSE, 31),
    (32, 1, '곰돌이 귀가 닿는 곳까지 마미케어', '귀여운 곰돌이 귀 모양 실리콘 진동클렌저가 새롭게 출시됐어요. 닿기 어려운 국소 부위까지 꼼꼼하게 딥클렌징할 수 있어요.', 'showcases/showcase_32.jpg', '2026-05-11', '2026-05-20', FALSE, 32),
    (33, 1, '정제된 멋의 아름다움 알리스', '미니멀리즘을 베이스로 핏과 소재, 원초적인 아름다움에 집중한 알리스. 현대적이면서도 감각적인 무드를 담아내는 정제된 멋의 아름다움을 지금 바로 소개할게요.', 'showcases/showcase_33.png', '2026-05-11', '2026-05-24', FALSE, 33),
    (34, 1, '시간이 빚어낸 우아함 르셉템버', '절제된 아름다움 속에서 발견하는 베이직의 가치. 미니멀한 실루엣과 차분한 톤으로 완성되는 여름 컬렉션을 만나보세요.', 'showcases/showcase_34.jpg', '2026-05-11', '2026-05-21', FALSE, 34),
    (35, 1, '오븐에서 식탁까지 쓰임', '조리와 플레이팅을 한 번에 완성하는 오븐글라스 시리즈를 만나보세요. 가볍게 차린 한 끼도 센스 있게 완성돼요.', 'showcases/showcase_35.jpg', '2026-05-11', '2026-05-24', FALSE, 35),
    (36, 1, '블랙 메쉬의 등장 헤라', 'NEW 블랙 쿠션 메쉬 파우더가 새롭게 론칭됐어요. 가볍게 밀착되는 클라우드 블러 스킨을 완성해보세요.', 'showcases/showcase_36.jpg', '2026-05-11', '2026-05-25', FALSE, 36),
    (37, 1, '위글위글과 함께하는 에스트라', '대한민국 1등 더마코스메틱 에스트라가 위글위글과 만났어요. 더마UV365로 매일 건강하게 피부를 지켜보세요.', 'showcases/showcase_37.jpg', '2026-05-11', '2026-05-25', FALSE, 37),
    (38, 1, '피부처럼 스며드는 편안함 휘게 언더웨어', '타협 없는 가치를 담은 노 와이어 심리스 속옷. 26SS 신상을 가장 먼저 만나보세요.', 'showcases/showcase_38.png', '2026-05-11', '2026-05-24', FALSE, 38),
    (39, 1, '올 여름 특별한 만남 락피쉬웨더웨어x오헤시오', '락피쉬웨더웨어와 오헤시오의 써머 협업 컬렉션을 소개합니다. 여름의 감성을 담은 다양한 디테일로 완성된 특별한 아이템을 만나보세요.', 'showcases/showcase_39.png', '2026-05-11', '2026-05-25', FALSE, 39),
    (40, 1, '위태로운 균형 위의 미학 포르테나', '평온해 보이는 공간 속에 은밀히 도사린 불안과 예민함, 그리고 그 위태로운 경계에서 피어나는 날이 선 취향에 대한 기록', 'showcases/showcase_40.jpg', '2026-05-11', '2026-05-24', FALSE, 40),
    (41, 1, '투명하게 번지는 여름빛 어패럴아카이브', '햇살이 부서지고 바람이 스치는 순간, 코끝에 머무는 싱그러움처럼 가볍고 맑은 계절을 담았어요. 심플함 속 담백함으로 일상을 채워보세요.', 'showcases/showcase_41.png', '2026-05-11', '2026-05-24', FALSE, 41),
    (42, 1, '시간이 남긴 흔적처럼 랑거', '입을수록 나를 닮아가는 옷. 워싱과 디테일로 완성한 빈티지 감성이 일상 속에서 자연스럽게 스며들어요. 여름의 뜨거운 공기 속에서도 편안하게 어울리는 랑거만의 무드를 만나보세요.', 'showcases/showcase_42.jpg', '2026-05-11', '2026-05-24', FALSE, 42),
    (43, 1, '푸른 바람이 불어오는 쏘이르', '하늘 아래 스치는 선선한 바람과 은은한 꽃의 색감을 담았어요. 가볍고 자연스러운 실루엣으로 편안하고 여유로운 여름을 만나보세요.', 'showcases/showcase_43.jpg', '2026-05-11', '2026-05-24', FALSE, 43),
    (44, 1, '일상에 스며드는 에센셜 노앙', '가장 기본적인 것들에 집중했어요. 군더더기 없는 실루엣과 편안한 구조로 하루의 흐름을 부드럽게 만들어줘요. 반복되는 일상 속 작은 변화의 컬러들이 자연스럽게 균형을 이뤄요.', 'showcases/showcase_44.jpg', '2026-05-11', '2026-05-24', FALSE, 44),
    (45, 1, '머리부터 마음까지 지비에이치', '트리트먼트와 스칼프 마사저가 만났어요. 손끝에서 시작된 부드러운 자극이 하루의 긴장을 풀어주고, 머릿결까지 촉촉하게 채워줍니다.', 'showcases/showcase_45.png', '2026-05-11', '2026-05-24', FALSE, 45),
    (46, 1, '자기표현의 시작 비엘티워크샵', '소비의 대상이 아닌, 나를 드러내는 매개체. 공간 속에서 나만의 이야기를 펼칠 수 있어요.', 'showcases/showcase_46.jpg', '2026-05-11', '2026-05-24', FALSE, 46),
    (47, 1, '본연의 빛을 깨우는 정샘물', 'NEW 글로이틴트가 새롭게 출시됐어요. 메이크업 아티스트의 손길처럼 자연스러운 광채를 선사하는 신상 틴트를 만나보세요. 특별한 증정 이벤트도 함께 준비했어요.', 'showcases/showcase_47.png', '2026-05-11', '2026-05-17', FALSE, 47),
    (48, 1, '산리오캐릭터즈와 만나 귀여움 두 배 바잇미', '사랑스러운 캐릭터 디자인에 바잇미의 감각적인 스타일을 더한 스페셜 컬렉션을 만나보세요.', 'showcases/showcase_48.png', '2026-05-11', '2026-05-24', FALSE, 48),
    (49, 2, '순수 비타민 C로 채우는 베이지크', '그린 커피빈의 항산화 효과로 피부 본연의 힘을 깨우는 슬로우 에이징. 순수 비타민 C 40% 캡슐팩으로 맑고 건강한 피부를 경험해보세요.', 'showcases/showcase_49.png', '2026-05-11', '2026-05-22', FALSE, 49),
    (50, 2, '하루를 위한 나만의 리추얼 아로마티카', '피부에 직접 닿는 순간, 자연의 힘이 전해집니다. 새롭게 선보이는 롤온 3종과 함께 언제 어디서나 자연 그대로의 케어를 경험해 보세요.', 'showcases/showcase_50.jpg', '2026-05-11', '2026-05-25', FALSE, 50),
    (51, 2, '클래식한 미니멀 코어 더 히어', '더 히어의 26SS 컬렉션은 일상 속 클래식한 디자인을 통해 특별한 순간을 포착하며, 그 찰나의 아름다움이 오래도록 기억에 잔잔히 남기를 바랍니다.', 'showcases/showcase_51.png', '2026-05-11', '2026-05-17', FALSE, 51),
    (52, 2, '햇살 아래 펼쳐지는 썸웨어버터', '2026 여름은 sunny side 위에서 펼쳐지는 자유로움을 담았습니다. 쉽게 끝나지 않는 계절의 활기 속에서 썸웨어버터가 그리는 여름을 제안합니다.', 'showcases/showcase_52.png', '2026-05-11', '2026-05-24', FALSE, 52),
    (53, 2, '달처럼 둥글게 담는 여유 바겐슈타이거', '소중하고 편안한 삶을 향한 첫 걸음. 명품 이상의 가치를 담은 달항아리 디자인 주방 컬렉션을 들여보세요.', 'showcases/showcase_53.jpg', '2026-05-11', '2026-05-24', FALSE, 53),
    (54, 2, '방 안에 핀 작은 정원 디어리얼', '블루가든 시리즈로 맞이하는 새 계절. 창밖의 하늘빛과 들판의 초록이 잔잔하게 번지는 시간을 경험해 보세요.', 'showcases/showcase_54.jpg', '2026-05-11', '2026-05-24', FALSE, 54),
    (55, 2, '피너츠 감성을 담은 요리 에지리', '80년 세월 동안 사랑받아온 법랑 쿡웨어에 피너츠의 유쾌함을 한 스푼 더했어요. 매일의 요리가 특별한 순간으로 바뀌어요.', 'showcases/showcase_55.jpg', '2026-05-11', '2026-05-24', FALSE, 55),
    (56, 2, '장인이 빚은 여름 감각 헬렌카민스키', '스리랑카의 영감을 담아 정교하게 완성한 컬렉션. 묵화와 함께하는 스타일링으로 특별한 여름을 누려보세요.', 'showcases/showcase_56.png', '2026-05-11', '2026-05-24', FALSE, 56),
    (57, 2, '여름이 머무는 고요한 결 이오테', '간결한 디자인과 차분한 무드로 일상에 자연스럽게 스며드는 여름의 순간. 새로운 컬렉션을 선보여요.', 'showcases/showcase_57.jpg', '2026-05-11', '2026-05-24', FALSE, 57),
    (58, 2, '여름의 가벼움을 담은 클래식한 실루엣 토르테', '클래식한 실루엣 위 소재와 균형에 집중했습니다. 간결한 디테일로 완성도를 높이고 계절의 가벼움을 담았습니다. 계절과 어울리는 절제된 아름다움 속에서 오래 함께할 봄을 제안합니다.', 'showcases/showcase_58.png', '2026-05-11', '2026-05-24', FALSE, 58),
    (59, 2, '가볍게 시작하는 여름 사뿐', '여름 신상 컬렉션을 소개합니다. 가벼운 발걸음으로 완성하는 당신만의 스타일을 만나보세요.', 'showcases/showcase_59.jpg', '2026-05-11', '2026-05-17', FALSE, 59),
    (60, 2, '푹신한 발걸음의 행복 토앤토', '산리오캐릭터즈와 함께하는 특별한 만남. 친환경 소재 제로비티로 가벼움과 편안함을 동시에 느껴보세요.', 'showcases/showcase_60.jpg', '2026-05-11', '2026-05-24', FALSE, 60),
    (61, 2, '사람과 삶을 잇는 하나의 스티치 피오티알', 'POTR CLAN은 각 색이 지닌 상징성과 감정적 의미를 디자인에 담아, 일상 속 새로운 감각과 특별한 경험을 제안하는 시리즈입니다.', 'showcases/showcase_61.jpg', '2026-05-11', '2026-05-24', FALSE, 61),
    (62, 2, '여름을 걷는 방법 위더로드', '클래식을 현대적으로 재해석한 위더로드의 피셔맨 샌들이 도착했어요. 미니멀한 디자인에 실용성을 더해 어디든 편안하게 어울려요.', 'showcases/showcase_62.jpg', '2026-05-11', '2026-05-24', FALSE, 62),
    (63, 2, '깊어진 여름의 보헤미안 튜드먼트', '자연스럽게 몸을 따라 흐르는 가벼운 실루엣. White bohemlook으로 완성된 이번 시즌, 꾸미지 않은 빈티지함이 담긴 튜드먼트만의 여름을 만나보세요.', 'showcases/showcase_63.jpg', '2026-05-11', '2026-05-24', FALSE, 63),
    (64, 2, '느긋한 일요일의 여름 셀리테일즈', '태양 아래 가장 선명하게 익어버린 우리의 여름. 시원한 토마토를 베어 문 찰나의 설렘처럼, 꾸밈없고 사랑스러운 순간들을 담았어요.', 'showcases/showcase_64.jpg', '2026-05-11', '2026-05-24', FALSE, 64),
    (65, 2, '생활을 이해하는 디자인 한샘', '수만 건의 주거 데이터를 바탕으로 탄생한 한샘 리빙 용품을 소개합니다. 실용성과 미감을 모두 갖춘 제품들로 당신의 공간에 새로운 감성을 더해보세요.', 'showcases/showcase_65.jpg', '2026-05-11', '2026-05-17', FALSE, 65),
    (66, 2, '이번 여름의 한 가지 마음 토마스모어', '더위에도 단정함을 잃지 않는 옷을 만들고 싶었어요. 린넨, 면, 레이온으로 완성한 여름 옷은 가벼우면서도 흐트러지지 않아 매일 자연스럽게 손이 갑니다.', 'showcases/showcase_66.png', '2026-05-11', '2026-05-24', FALSE, 66),
    (67, 2, '감도 높은 나만의 공간 피아바', '매일 같은 자리에 놓여 있어도 설레는 순간. 감각적이면서 실용적인 피아바의 신상들이 일상에 특별함을 더해요.', 'showcases/showcase_67.jpg', '2026-05-11', '2026-05-24', FALSE, 67),
    (68, 2, '조용히 드러나는 선 아우로', '아우로의 2026 여름 컬렉션을 소개합니다. 부드럽게 흐르는 실루엣과 은은한 텍스쳐, 절제된 디테일이 만드는 선명한 이끌림을 경험해 보세요.', 'showcases/showcase_68.jpg', '2026-05-10', '2026-05-23', FALSE, 68),
    (69, 2, '편안함이 완성하는 하루 뉴발란스', '플랫 브리즈가 당신의 발에 새로운 균형을 선사해요. 오래 걸어도 편안한 하루를 만들어 줄 거예요.', 'showcases/showcase_69.jpg', '2026-05-08', '2026-05-21', FALSE, 69),
    (70, 2, '반짝이는 만남 오찌 x 유희', 'OTZ와 YOUHEE가 만나 더욱 특별한 컬렉션을 선보입니다. 조금 더 몽환적이고, 유치하며, 때로는 예측할 수 없는 방향으로 전개되는 이번 컬렉션은 걸리시한 무드의 메리제인 슈즈', 'showcases/showcase_70.jpg', '2026-05-08', '2026-05-21', FALSE, 70),
    (71, 2, '빛이 기록하는 여름 테누브', '새로운 계절의 시작, 테누브 26 여름 컬렉션이 도착했어요. 빛과 감정의 잔상을 담은 여유로운 순간을 만나보세요.', 'showcases/showcase_71.jpg', '2026-05-08', '2026-05-21', FALSE, 71),
    (72, 2, '세상에 없던 새로운 형태 버미큘라', '깊은 형태와 스파웃 디자인으로 수프는 물론 다양한 요리가 가능한 멀티팟을 소개해요. 숙련된 장인의 기술력으로 완성한 프리미엄 주물 냄비를 만나보세요.', 'showcases/showcase_72.jpg', '2026-05-08', '2026-05-21', FALSE, 72),
    (73, 2, '가장 정적인 순간의 여름 오데스', '익숙한 일상 속에서 발견한 새로운 흐름. 과하지 않은 실루엣 안에 숨겨진 의외의 디테일이 조용한 존재감을 완성해요.', 'showcases/showcase_73.png', '2026-05-08', '2026-05-21', FALSE, 73),
    (74, 2, '여름에도 편안한 걸음 코모레비뮤지엄', '25년 장인의 손길이 담긴 수제화. 인체공학적 설계로 발을 감싸는 착화감이 여름에도 가볍게 이어져요.', 'showcases/showcase_74.jpg', '2026-05-08', '2026-05-21', FALSE, 74),
    (75, 2, '기분 좋은 아침을 위한 선물 웜그레이테일', '코튼모달 3중직 블랭킷과 쿠션 세트, 신규 타월 컬렉션을 소개해요. 프리미엄 모달 소재의 부드러운 촉감과 통기성으로 좋은 하루 만들어요.', 'showcases/showcase_75.jpg', '2026-05-08', '2026-05-21', FALSE, 75),
    (76, 2, '연우가 선택한 여름 라미네즈', '인플루언서 연우가 먼저 만난 여름 신상을 선보입니다. 감각적인 디테일이 더해진 특별한 실루엣을 지금 만나보세요.', 'showcases/showcase_76.jpg', '2026-05-08', '2026-05-21', FALSE, 76),
    (77, 2, '여름날의 감각 뚜누', '기억에 남지 않던 날들 속 특별한 장면들을 모았어요. 잔잔한 텍스트와 바다 조각 패턴, 시원한 터치감이 하나의 컬렉션 안에서 자연스럽게 이어집니다.', 'showcases/showcase_77.jpg', '2026-05-08', '2026-05-19', FALSE, 77),
    (78, 2, '조용히 스며든 여름', '빛과 그림자가 교차하는 여름의 순간들, 자연스러운 움직임과 편안함을 담은 링서울의 여름을 전합니다.', 'showcases/showcase_78.jpg', '2026-05-08', '2026-05-21', FALSE, 78),
    (79, 2, '일상에 부드럽게 스며드는 글로니', '아름다움과 편안함을 공존하는 매 순간을 위한 글로니의 서머 클래식 컬렉션을 만나보세요. 여름의 가벼운 무드를 담아 가볍고 자유로운 실루엣으로 완성했습니다.', 'showcases/showcase_79.jpg', '2026-05-08', '2026-05-21', FALSE, 79),
    (80, 2, '여름과 어우러지는 차분함 고낙', '선과 선이 만나 완성되는 입체적인 형태. 정제되지 않은 자연스러움이 여름의 뜨거운 공기와 조화를 이뤄요. 좋은 소재와 세심한 패턴으로 만든 특별한 옷을 만나보세요.', 'showcases/showcase_80.jpg', '2026-05-07', '2026-05-20', FALSE, 80),
    (81, 2, '액티브한 여름 발견 디스커버리 익스페디션', '발걸음이 액티브할수록 하루도 액티브해지는 디스커버리 익스페디션 26SS 컬렉션을 만나요.', 'showcases/showcase_81.jpg', '2026-05-07', '2026-05-20', FALSE, 81),
    (82, 2, '뜨거운 날씨 속 쾌적함 썬러브', '고기능성 소재와 캐주얼한 디자인이 만난 pulse 네 번째 챕터를 소개해요. 흡습속건과 경량성을 갖춘 원단으로 활동적인 여름을 더욱 편안하게 보낼 수 있어요.', 'showcases/showcase_82.jpg', '2026-05-07', '2026-05-20', FALSE, 82),
    (83, 2, '성장하는 순간 속에서 두두앤솜', '아이의 감정으로 담아낸 일본 작은 소도시의 장면들. 그 시간을 지나, 집처럼 편안함이 느껴지는 두두앤솜 두번째 여름 컬렉션을 만나보세요.', 'showcases/showcase_83.jpg', '2026-05-07', '2026-05-13', FALSE, 83),
    (84, 2, '시간을 남기는 태도, 나이키', '시간을 수집하듯 하루를 새기는 태도. 나이키 문슈가 남기는 흔적을 29CM와 함께 이어가요.', 'showcases/showcase_84.jpg', '2026-05-07', '2026-05-20', FALSE, 84),
    (85, 2, '깨끗한 공기를 채우는 리슬립', '수면 전문가들과 함께 연구한 고체탈취제가 새롭게 출시됐어요. 피톤치드로 완성한 깨끗한 수면 환경을 경험해 보세요.', 'showcases/showcase_85.jpg', '2026-05-07', '2026-05-13', FALSE, 85),
    (86, 2, '장인의 손끝에서 완성되는 구두 포스트맨', '악천후 조차 당신의 여정이 됩니다. 거친 길 위에서 더 빛나는 프렌치 U-Tip 더비 포스트맨 26 S/S 프리미엄 라인 로버 컬렉션을 만나보세요.', 'showcases/showcase_86.png', '2026-05-07', '2026-05-20', FALSE, 86),
    (87, 2, '캔디 파라다이스로의 초대 에즈이프캘리', '선명한 팝 컬러와 경쾌한 무드가 만드는 여름의 한가운데. 지구와 함께하는 이번 시즌, 톡톡 튀는 컬러감으로 나만의 작은 휴식을 즐겨보세요.', 'showcases/showcase_87.jpg', '2026-05-07', '2026-05-20', FALSE, 87),
    (88, 2, '매일 입고 싶은 클래식 파르티멘토 우먼', '기본에 충실하면서도 나만의 개성을 담아낼 수 있는 영 캐주얼 컨템퍼러리 무드. 트렌디하면서도 합리적인 가격의 상품을 만나보세요.', 'showcases/showcase_88.jpg', '2026-05-07', '2026-05-20', FALSE, 88),
    (89, 2, '자연스러운 휴식 유라고', '하루의 시작과 끝, 어떤 시간에도 자연스럽게 스며드는 나만의 휴식에 어울리는 유라고의 두 번째 홈웨어입니다.', 'showcases/showcase_89.jpg', '2026-05-07', '2026-05-20', FALSE, 89),
    (90, 2, '꾸민 듯 꾸미지 않은 여름 에이에이유', '인위적인 꾸밈 대신 자연스러운 멋을 담았어요. 당신의 몸에 맞춘 듯한 편안함과 격식 없이 활용하기 좋은 아이템으로 매일을 완성해보세요.', 'showcases/showcase_90.jpg', '2026-05-07', '2026-05-20', FALSE, 90),
    (91, 2, '함께라서 더 가벼운 하루 코오롱스포츠', '여름 데이팩과 함께 가벼운 발걸음으로 떠나보세요. 자연 속에서 발견하는 일상의 의미, 코오롱스포츠가 함께합니다.', 'showcases/showcase_91.jpg', '2026-05-07', '2026-05-20', FALSE, 91),
    (92, 2, '공기가 가벼워지는 순간 위드아웃썸머', '익숙한 일상 속에서도 새롭게 돋는 생기를 담았어요. 빈티지 무드가 자연스럽게 스며드는 러블리 캐쥬얼룩을 만나보세요.', 'showcases/showcase_92.jpg', '2026-05-07', '2026-05-20', FALSE, 92),
    (93, 2, '감성 가득한 테이블 앨리건트테이블', '일상에 즐거움을 더하는 테이블웨어를 만나보세요. 사랑스러운 신제품으로 분위기 있는 테이블을 완성할 수 있어요.', 'showcases/showcase_93.jpg', '2026-05-07', '2026-05-20', FALSE, 93),
    (94, 2, '매일의 점심시간이 즐거워지는 하우키즈풀', '위트 있는 그래픽과 실용적인 디자인이 담긴 런치백 신상 소식을 전해요. 정확한 색감으로 일상에 생기를 더해보세요.', 'showcases/showcase_94.jpg', '2026-05-07', '2026-05-13', FALSE, 94),
    (95, 2, '공간에 스며드는 온기 아이엔지홈', '새로운 랙 책장이 찾아왔어요. 단순한 수납을 넘어 공간 전체에 감성을 불어넣는 디자인 가구를 경험해보세요.', 'showcases/showcase_95.jpg', '2026-05-07', '2026-05-20', FALSE, 95),
    (96, 2, '간결한 실루엣과 가볍게 스며드는 착용감 네세서리', '가장 뜨거운 계절, 우아한 일관성을 뒷받침할 가장 명확한 선택, 네세서리에서 만나보세요.', 'showcases/showcase_96.jpg', '2026-05-07', '2026-05-20', FALSE, 96);
